#include <iostream>
#include <cmath>
#include <vector>
#include <iomanip>

using namespace std;

// Function to generate a sequence of numbers
vector<int> generateSequence(int n) {
    vector<int> sequence;
    for (int i = 0; i < n; ++i) {
        sequence.push_back(i * 2 + 1);
    }
    return sequence;
}

// Function to print the pattern
void printPattern(int size, vector<int> sequence) {
    for (int i = 0; i < size; ++i) {
        for (int j = 0; j < size; ++j) {
            // Calculate the value based on the sequence
            int value = sequence[i] + sequence[j];
            // Display the value with appropriate formatting
            cout << setw(4) << value;
        }
        cout << endl;
    }
}

int main() {
    int size = 5;
    vector<int> sequence = generateSequence(size);

    cout << "Generated sequence: ";
    for (int num : sequence) {
        cout << num << " ";
    }
    cout << endl;

    printPattern(size, sequence);

    return 0;
}
```

